module.exports = /*#__PURE__*/JSON.parse('{"language":"en","name":"English","globalRules":{"outputLanguage":"English","preserveRegister":false,"avoidTranslationese":false,"preserveSocialPronouns":false},"actionPrompts":{"continue_writing":{"task":"Continue writing the story prose naturally from the cursor state.","rules":"1. Continue from the exact current narrative state.\\n2. Preserve POV, tense, tone, and pacing from the context.\\n3. Use Characters.md to keep character motivations, relationships, and speech patterns consistent.\\n4. Use hidden continuity memory to avoid contradictions.\\n5. Do not resolve conflict too quickly.\\n6. Do not invent major canon facts unless clearly implied or requested.\\n7. Write approximately 150 words.","outputFormat":"Return only the continued story prose. Do not include commentary, labels, explanations, markdown fences, or surrounding quotation marks."},"rewrite_selection":{"task":"Rewrite the selected passage based on the author\'s instructions.","rules":"1. Keep the same core narrative actions, plot points, and character positions.\\n2. Apply the style guide from Style.md strictly to narration, descriptions, and pacing.\\n3. Match characters and continuity from Characters.md.\\n4. Do not invent new narrative facts unless explicitly requested.\\n5. Match the length of the original selection unless instructions say otherwise.","outputFormat":"Return the rewritten passage only. Do not include commentary, labels, explanations, markdown fences, or surrounding quotation marks."},"expand_selection":{"task":"Add depth, atmosphere, interiority, sensory detail, or subtext to the selection.","rules":"1. Preserve original plot direction.\\n2. Add depth, description, or character thought without changing core events.\\n3. Do not introduce major new facts unless requested.\\n4. Preserve POV, tense, tone, and character voice.","outputFormat":"Return the expanded passage only. Do not include commentary, labels, explanations, markdown fences, or surrounding quotation marks."},"tighten_selection":{"task":"Condense and tighten the selected text to make the prose sharper, faster, or more active.","rules":"1. Remove fluff, passive voice, wordiness, or repetitive descriptions.\\n2. Preserve the full sequence of events and information.\\n3. Preserve character voice and registers from Characters.md.","outputFormat":"Return the tightened passage only. Do not include commentary, labels, explanations, markdown fences, or surrounding quotation marks."},"improve_dialogue":{"task":"Revise and polish the dialogue in the selection to sound natural, characteristic, and impactful.","rules":"1. Ensure distinct speech styles matching the character voices from Characters.md.\\n2. Match correct relationship pronouns (especially for Vietnamese social registers).\\n3. Keep dialogue active, subtextual, and expressive.\\n4. Do not change surrounding narration unless necessary to support the revised dialogue.","outputFormat":"Return the polished passage only. Do not include commentary, labels, explanations, markdown fences, or surrounding quotation marks."},"extract_style":{"task":"Extract a structured, reusable style and voice profile from the user\'s prose sample or notes.","rules":"1. Convert vague style preferences into concrete, actionable writing guidance.\\n2. Do not imitate copyrighted text directly.\\n3. Do not overfit to one passage.\\n4. Describe sentence rhythm, description style, dialogue style, emotional style, pacing, preferred techniques, things to avoid, and sample passages.\\n5. Keep the output practical for future novel-writing prompts.","outputFormat":"Return a complete updated Style.md using this structure:\\n\\n# Style\\n\\n## Style Summary\\n\\n## Sentence Rhythm\\n\\n## Description Style\\n\\n## Dialogue Style\\n\\n## Emotional Style\\n\\n## Pacing\\n\\n## Preferred Techniques\\n\\n## Avoid\\n\\n## Reference Influences\\n\\n## Extracted Voice Notes\\n\\n## Sample Passage"},"capture_characters":{"task":"Extract character information from the target text and format as a structured JSON list of characters.","rules":"1. Extract only character-relevant information.\\n2. Deduplicate characters by name.\\n3. Capture aliases, traits, role, status, age, appearance, voice, coreDesire, coreFear, relationships, and secrets.\\n4. Do not include quotes or surrounding text, just the raw JSON array inside a markdown block.","outputFormat":"Return only a JSON array matching the Character schema. Example:\\n[\\n  {\\n    \\"name\\": \\"Sarah Vance\\",\\n    \\"aliases\\": [\\"Sarah\\", \\"Vance\\"],\\n    \\"role\\": \\"protagonist\\",\\n    \\"appearance\\": \\"Scarred ex-sailor...\\",\\n    \\"traits\\": [\\"stoic\\", \\"stubborn\\"],\\n    \\"secrets\\": [\\"Fear of open ocean\\"]\\n  }\\n]"},"summarize_continuity":{"task":"Create or update the timeline, plot state, facts, open questions, and threads in the Continuity.md memory.","rules":"1. Summarize only accepted story progress.\\n2. Keep continuity memory compact.\\n3. Track timeline, plot progress, confirmed facts, open questions, unresolved threads, relationship changes, and continuity risks.\\n4. Do not rewrite prose.\\n5. Do not change Project.md, Style.md, or Characters.md.\\n6. Do not treat ambiguous implications as confirmed facts.","outputFormat":"Return complete updated Continuity Memory using this structure:\\n\\n# Continuity Memory\\n\\n## Full Story Summary\\n\\n## Chapter Summaries\\n\\n## Timeline\\n\\n## Plot Progress\\n\\n## Confirmed Facts\\n\\n## Character State Changes\\n\\n## Relationship Changes\\n\\n## World / Setting Facts\\n\\n## Open Questions\\n\\n## Unresolved Threads\\n\\n## Continuity Risks"},"check_continuity":{"task":"Analyze the selected text or chapter against the Project.md, Characters.md, and Continuity.md to detect anomalies, timeline clashes, or character behavior inconsistencies.","rules":"1. Contrast scene events against canonical constraints in Project.md.\\n2. Identify character voice, relationship, or secret clashes against Characters.md.\\n3. Identify timeline gaps, plot breaches, or setting errors against Continuity.md.\\n4. Classify issues as high (direct clash), medium (subtle logic risk), or low (cosmetic/stylistic gap).\\n5. Propose constructive stylistic adjustments.","outputFormat":"Return an analysis report with these sections:\\n\\n# Continuity Analysis Report\\n\\n## High Priority Issues (Direct Clashes)\\n\\n## Medium Priority Issues (Subtle Risks)\\n\\n## Minor Issues & Suggestions\\n\\n## Stylistic Voice Consistency Checks"},"beat_write":{"task":"Write vivid story prose that conveys a specific scene beat target.","rules":"1. Write 1 to 3 paragraphs of high-quality narrative prose.\\n2. Strictly target the specified beat description and narrative intent.\\n3. Preserve the POV, tense, tone, style guidelines from Style.md, and pacing from the context.\\n4. Maintain character motives, relationships, and speech patterns from Characters.md.\\n5. Integrate seamlessly and transition naturally between the preceding and following prose context.","outputFormat":"Return only the generated story prose. Do not include commentary, labels, explanations, markdown fences, or surrounding quotation marks."}}}');

